function getUsedPlayerTitlesFromRoster(rosterData) {
  return (Array.isArray(rosterData) ? rosterData : [])
    .filter((entry) => entry.name !== MASTER_NAME && entry.title !== MASTER_TITLE)
    .map((entry) => entry.title)
    .filter(Boolean);
}

function pickRandomPlayerTitle(usedTitles) {
  const used = new Set(usedTitles || []);
  const remaining = PLAYER_TITLES.filter((t) => !used.has(t.title));
  if (remaining.length === 0) return null;
  return remaining[Math.floor(Math.random() * remaining.length)];
}

function makeDisplayName(name, title) {
  return `${title} (${name})`;
}

function normalizeLatestProfileImage(entry) {
  if (!entry) return entry;
  const text = `${entry.title || ""} ${entry.displayName || ""} ${entry.name || ""}`;
  if (text.includes("리센느") || text.includes("RESCENE") || text.includes("미나미") || text.includes("거제")) {
    return { ...entry, img: IMG_MINAMI };
  }
  return entry;
}

function normalizeRosterImages(rosterData) {
  return (Array.isArray(rosterData) ? rosterData : []).map(normalizeLatestProfileImage);
}

function normalizeMembersImages(membersData) {
  const normalized = {};
  Object.entries(membersData || {}).forEach(([key, entries]) => {
    normalized[key] = (Array.isArray(entries) ? entries : []).map(normalizeLatestProfileImage);
  });
  return normalized;
}

// ───────────────────────────────────────────────
// 스코어 확률
// home = 남아공 골수, away = 한국 골수
// ───────────────────────────────────────────────
const REAL_PROBS = {
  "0-1": 0.13, "0-2": 0.12, "1-1": 0.11, "0-0": 0.08, "1-2": 0.10,
  "0-3": 0.07, "1-0": 0.06, "1-3": 0.06, "2-1": 0.05, "2-2": 0.04,
  "0-4": 0.03, "2-0": 0.03, "1-4": 0.02, "3-2": 0.02, "3-1": 0.01,
};

function factorial(n) {
  let result = 1;
  for (let i = 2; i <= n; i++) result *= i;
  return result;
}

function poisson(lambda, k) {
  return (Math.pow(lambda, k) * Math.exp(-lambda)) / factorial(k);
}

const LAMBDA_RSA = 0.8;
const LAMBDA_KOR = 1.7;

function buildScores() {
  const emojiPool = ["😬","🤝","💤","📉","🔥","😤","🎉","🥶","🍿","🚀","🐯","😭","😱","🤯","🥳","😵","🙃","😎","🫠","🤡","🫨","🥴","😶‍🌫️","🤪","🦴"];
  const raw = [];

  for (let m = 0; m <= 4; m++) {
    for (let k = 0; k <= 4; k++) {
      const key = `${m}-${k}`;
      const prob = REAL_PROBS[key] != null
        ? REAL_PROBS[key]
        : poisson(LAMBDA_RSA, m) * poisson(LAMBDA_KOR, k) * 0.6;

      raw.push({
        home: m,
        away: k,
        label: `한국 ${k} : ${m} 남아공`,
        prob,
        source: REAL_PROBS[key] != null ? "real" : "est",
      });
    }
  }

  const sumRaw = raw.reduce((a, b) => a + b.prob, 0);
  const bigDiffProb = Math.max(0.01, 1 - sumRaw);
  raw.push({ home: "5+", away: "KOR", label: "한국 5점차 이상 대승", prob: bigDiffProb / 2, source: "est" });
  raw.push({ home: "5+", away: "RSA", label: "한국 5점차 이상 대패", prob: bigDiffProb / 2, source: "est" });

  const sorted = [...raw].sort((a, b) => b.prob - a.prob);
  const n = sorted.length;

  sorted.forEach((s, idx) => {
    const bucket = Math.floor((idx / n) * 7) + 1;
    s.hours = Math.min(bucket, 7);
  });

  sorted.filter((s) => s.home === "5+").forEach((s) => {
    s.hours = 7;
  });

  const display = [...sorted].sort((a, b) => {
    if (a.hours !== b.hours) return a.hours - b.hours;
    return b.prob - a.prob;
  });

  return display.map((s, i) => ({
    ...s,
    emoji: emojiPool[i % emojiPool.length],
  }));
}

const SCORES = buildScores();

// ───────────────────────────────────────────────
// D-day
// ───────────────────────────────────────────────
const MATCH_TIME = new Date("2026-06-25T10:00:00+09:00");

function getDday() {
  const now = new Date();
  const diffMs = MATCH_TIME.getTime() - now.getTime();
  if (diffMs <= 0) return null;

  const toKstDateOnly = (d) => {
    const kst = new Date(d.getTime() + 9 * 60 * 60 * 1000);
    return Date.UTC(kst.getUTCFullYear(), kst.getUTCMonth(), kst.getUTCDate());
  };

  return Math.round((toKstDateOnly(MATCH_TIME) - toKstDateOnly(now)) / (1000 * 60 * 60 * 24));
}

function getDdayLabel() {
  const diffDays = getDday();

  if (diffDays === null || diffDays <= 0) {
    return "🌙 FINAL STAGE D-DAY! 새로운 별이 무대에 오릅니다";
  }
  if (diffDays === 1) {
    return "✨ FINAL STAGE D-1! 꿈의 무대가 코앞입니다";
  }
  return `⏳ FINAL STAGE까지 D-${diffDays}`;
}

